  recordEvalFixtureApproval({
    runnerReceiptId = null,
    publicationReceiptId = null,
    approvalKind = 'operator_fixture_approval',
    decision = 'approved_for_non_live_fixture',
    mode = 'local_review',
    status = 'approved_blocked_publication',
    summary = '',
    evidence = null,
    now = Date.now()
  } = {}) {
    const normalizedMode = normalizePortfolioStatus(mode, 'local_review');
    if (!['local_review', 'dry_run'].includes(normalizedMode)) {
      throw new Error('eval fixture approval receipts are local_review/dry_run only');
    }
    let runnerReceipt = runnerReceiptId ? this.getEvalFixtureRunnerReceipt(runnerReceiptId) : null;
    if (!runnerReceipt && publicationReceiptId) {
      runnerReceipt = this.listEvalFixtureRunnerReceipts({ publicationReceiptId, limit: 1 })[0] || null;
    }
    if (!runnerReceipt) throw new Error(`eval fixture runner receipt not found for fixture approval: ${runnerReceiptId || publicationReceiptId || 'missing'}`);
    if (runnerReceipt.status !== 'blocked_runner_dry_run') {
      throw new Error('blocked runner dry-run receipt required before fixture approval');
    }
    const publicationReceipt = this.getEvalPublicationReceipt(runnerReceipt.publication_receipt_id);
    if (!publicationReceipt) throw new Error(`eval publication receipt not found for fixture approval: ${runnerReceipt.publication_receipt_id}`);
    const learningRecord = hydratePortfolioRow(db.prepare(`SELECT * FROM portfolio_learning_records WHERE id = ?`).get(runnerReceipt.learning_record_id));
    if (!learningRecord) throw new Error(`learning record not found for eval fixture approval: ${runnerReceipt.learning_record_id}`);
    if (learningRecord.status !== 'accepted_eval_artifact') {
      throw new Error('accepted eval artifact required before fixture approval');
    }
    const closeout = runnerReceipt.closeout_id ? this.getHandoffEvalCloseout(runnerReceipt.closeout_id) : null;
    const approval = normalizeEvalFixtureApprovalReceipt({
      runnerReceipt,
      publicationReceipt,
      closeout,
      learningRecord,
      approvalKind,
      decision,
      mode: normalizedMode,
      status,
      summary,
      evidence,
      now
    });
    const currentEval = learningRecord.eval && typeof learningRecord.eval === 'object' ? learningRecord.eval : {};
    const apply = db.transaction(() => {
      db.prepare(`
        INSERT OR IGNORE INTO portfolio_eval_fixture_approval_receipts (
          id, workspace_id, service_business_id, runner_receipt_id, publication_receipt_id, closeout_id,
          learning_record_id, eval_key, approval_kind, decision, mode, status, summary,
          request_json, response_json, evidence_json, created_at, updated_at
        )
        VALUES (
          @id, @workspace_id, @service_business_id, @runner_receipt_id, @publication_receipt_id, @closeout_id,
          @learning_record_id, @eval_key, @approval_kind, @decision, @mode, @status, @summary,
          @request_json, @response_json, @evidence_json, @created_at, @updated_at
        )
      `).run(approval);
      const persistedReceipt = db.prepare(`
        SELECT *
        FROM portfolio_eval_fixture_approval_receipts
        WHERE runner_receipt_id = ? AND approval_kind = ?
        ORDER BY created_at DESC
        LIMIT 1
      `).get(runnerReceipt.id, approval.approval_kind);
      db.prepare(`
        UPDATE portfolio_learning_records
        SET eval_json = ?,
            updated_at = ?
        WHERE id = ?
      `).run(jsonText({
        ...currentEval,
        fixtureApprovalRecorded: true,
        fixtureApprovalReceiptId: persistedReceipt?.id || approval.id,
        fixtureApprovalDecision: approval.decision,
        fixtureApprovedForNonLiveRunner: approval.decision === 'approved_for_non_live_fixture',
        executablePublicationAllowed: false,
        harnessExecuted: false,
        testFileWritten: false,
        ciWorkflowMutated: false,
        liveSideEffectsAllowed: false
      }), now, learningRecord.id);
      insertPortfolioEvent({
        workspaceId: approval.workspace_id,
        entityType: 'eval_fixture_approval_receipt',
        entityId: persistedReceipt?.id || approval.id,
        type: 'portfolio_eval.fixture_approval_recorded',
        summary: approval.summary,
        metadata: {
          serviceBusinessId: approval.service_business_id,
          runnerReceiptId: approval.runner_receipt_id,
          publicationReceiptId: approval.publication_receipt_id,
          learningRecordId: approval.learning_record_id,
          evalKey: approval.eval_key,
          decision: approval.decision
        },
        now
      });
    });
    apply();
    return {
      receipt: this.getEvalFixtureApprovalReceipt(approval.id)
        || this.listEvalFixtureApprovalReceipts({ runnerReceiptId: runnerReceipt.id, approvalKind: approval.approval_kind, limit: 1 })[0],
      runnerReceipt: this.getEvalFixtureRunnerReceipt(runnerReceipt.id),
      publicationReceipt: this.getEvalPublicationReceipt(publicationReceipt.id),
      closeout: closeout?.id ? this.getHandoffEvalCloseout(closeout.id) : null,
      learningRecord: hydratePortfolioRow(db.prepare(`SELECT * FROM portfolio_learning_records WHERE id = ?`).get(learningRecord.id))
    };
  },

