  recordEvalNonLiveRunnerBinding({
    goldenReviewReceiptId = null,
    approvalReceiptId = null,
    runnerReceiptId = null,
    publicationReceiptId = null,
    bindingKind = 'non_live_runner_binding',
    decision = 'runner_bound_non_live',
    mode = 'dry_run',
    status = 'bound_blocked_publication',
    summary = '',
    evidence = null,
    now = Date.now()
  } = {}) {
    const normalizedMode = normalizePortfolioStatus(mode, 'dry_run');
    if (!['dry_run', 'local_review'].includes(normalizedMode)) {
      throw new Error('eval non-live runner binding receipts are dry_run/local_review only');
    }
    let goldenReviewReceipt = goldenReviewReceiptId ? this.getEvalGoldenFixtureReviewReceipt(goldenReviewReceiptId) : null;
    if (!goldenReviewReceipt && approvalReceiptId) {
      goldenReviewReceipt = this.listEvalGoldenFixtureReviewReceipts({ approvalReceiptId, limit: 1 })[0] || null;
    }
    if (!goldenReviewReceipt && runnerReceiptId) {
      goldenReviewReceipt = this.listEvalGoldenFixtureReviewReceipts({ runnerReceiptId, limit: 1 })[0] || null;
    }
    if (!goldenReviewReceipt && publicationReceiptId) {
      goldenReviewReceipt = this.listEvalGoldenFixtureReviewReceipts({ publicationReceiptId, limit: 1 })[0] || null;
    }
    if (!goldenReviewReceipt) throw new Error(`eval golden fixture review receipt not found for non-live runner binding: ${goldenReviewReceiptId || approvalReceiptId || runnerReceiptId || publicationReceiptId || 'missing'}`);
    if (goldenReviewReceipt.status !== 'reviewed_blocked_publication') {
      throw new Error('reviewed blocked publication golden fixture receipt required before non-live runner binding');
    }
    if (goldenReviewReceipt.decision !== 'golden_fixture_accepted') {
      throw new Error('accepted golden fixture decision required before non-live runner binding');
    }
    const approvalReceipt = this.getEvalFixtureApprovalReceipt(goldenReviewReceipt.approval_receipt_id);
    if (!approvalReceipt) throw new Error(`eval fixture approval receipt not found for non-live runner binding: ${goldenReviewReceipt.approval_receipt_id}`);
    const runnerReceipt = this.getEvalFixtureRunnerReceipt(goldenReviewReceipt.runner_receipt_id);
    if (!runnerReceipt) throw new Error(`eval fixture runner receipt not found for non-live runner binding: ${goldenReviewReceipt.runner_receipt_id}`);
    const publicationReceipt = this.getEvalPublicationReceipt(goldenReviewReceipt.publication_receipt_id);
    if (!publicationReceipt) throw new Error(`eval publication receipt not found for non-live runner binding: ${goldenReviewReceipt.publication_receipt_id}`);
    const learningRecord = hydratePortfolioRow(db.prepare(`SELECT * FROM portfolio_learning_records WHERE id = ?`).get(goldenReviewReceipt.learning_record_id));
    if (!learningRecord) throw new Error(`learning record not found for eval non-live runner binding: ${goldenReviewReceipt.learning_record_id}`);
    if (learningRecord.status !== 'accepted_eval_artifact') {
      throw new Error('accepted eval artifact required before non-live runner binding');
    }
    const closeout = goldenReviewReceipt.closeout_id ? this.getHandoffEvalCloseout(goldenReviewReceipt.closeout_id) : null;
    const binding = normalizeEvalNonLiveRunnerBindingReceipt({
      goldenReviewReceipt,
      approvalReceipt,
      runnerReceipt,
      publicationReceipt,
      closeout,
      learningRecord,
      bindingKind,
      decision,
      mode: normalizedMode,
      status,
      summary,
      evidence,
      now
    });
    const currentEval = learningRecord.eval && typeof learningRecord.eval === 'object' ? learningRecord.eval : {};
    const apply = db.transaction(() => {
      db.prepare(`
        INSERT OR IGNORE INTO portfolio_eval_non_live_runner_binding_receipts (
          id, workspace_id, service_business_id, golden_review_receipt_id, approval_receipt_id, runner_receipt_id,
          publication_receipt_id, closeout_id, learning_record_id, eval_key, binding_kind, decision, mode, status,
          summary, request_json, response_json, evidence_json, created_at, updated_at
        )
        VALUES (
          @id, @workspace_id, @service_business_id, @golden_review_receipt_id, @approval_receipt_id, @runner_receipt_id,
          @publication_receipt_id, @closeout_id, @learning_record_id, @eval_key, @binding_kind, @decision, @mode, @status,
          @summary, @request_json, @response_json, @evidence_json, @created_at, @updated_at
        )
      `).run(binding);
      const persistedReceipt = db.prepare(`
        SELECT *
        FROM portfolio_eval_non_live_runner_binding_receipts
        WHERE golden_review_receipt_id = ? AND binding_kind = ?
        ORDER BY created_at DESC
        LIMIT 1
      `).get(goldenReviewReceipt.id, binding.binding_kind);
      db.prepare(`
        UPDATE portfolio_learning_records
        SET eval_json = ?,
            updated_at = ?
        WHERE id = ?
      `).run(jsonText({
        ...currentEval,
        nonLiveRunnerBindingRecorded: true,
        nonLiveRunnerBindingReceiptId: persistedReceipt?.id || binding.id,
        nonLiveRunnerBindingDecision: binding.decision,
        nonLiveRunnerBound: binding.decision === 'runner_bound_non_live',
        runnerCommandExecuted: false,
        executablePublicationAllowed: false,
        harnessExecuted: false,
        testFileWritten: false,
        ciWorkflowMutated: false,
        liveSideEffectsAllowed: false
      }), now, learningRecord.id);
      insertPortfolioEvent({
        workspaceId: binding.workspace_id,
        entityType: 'eval_non_live_runner_binding_receipt',
        entityId: persistedReceipt?.id || binding.id,
        type: 'portfolio_eval.non_live_runner_binding_recorded',
        summary: binding.summary,
        metadata: {
          serviceBusinessId: binding.service_business_id,
          goldenReviewReceiptId: binding.golden_review_receipt_id,
          approvalReceiptId: binding.approval_receipt_id,
          runnerReceiptId: binding.runner_receipt_id,
          publicationReceiptId: binding.publication_receipt_id,
          learningRecordId: binding.learning_record_id,
          evalKey: binding.eval_key,
          decision: binding.decision
        },
        now
      });
    });
    apply();
    return {
      receipt: this.getEvalNonLiveRunnerBindingReceipt(binding.id)
        || this.listEvalNonLiveRunnerBindingReceipts({ goldenReviewReceiptId: goldenReviewReceipt.id, bindingKind: binding.binding_kind, limit: 1 })[0],
      goldenReviewReceipt: this.getEvalGoldenFixtureReviewReceipt(goldenReviewReceipt.id),
      approvalReceipt: this.getEvalFixtureApprovalReceipt(approvalReceipt.id),
      runnerReceipt: this.getEvalFixtureRunnerReceipt(runnerReceipt.id),
      publicationReceipt: this.getEvalPublicationReceipt(publicationReceipt.id),
      closeout: closeout?.id ? this.getHandoffEvalCloseout(closeout.id) : null,
      learningRecord: hydratePortfolioRow(db.prepare(`SELECT * FROM portfolio_learning_records WHERE id = ?`).get(learningRecord.id))
    };
  },

