  recordEvalPrOpenSimulation({
    prMergeProposalReceiptId = null,
    generatedArtifactPromotionReceiptId = null,
    simulationKind = 'pr_open_simulation',
    decision = 'pr_open_simulated_not_submitted',
    mode = 'local_review',
    status = 'pr_open_simulated_blocked_submission',
    summary = '',
    evidence = null,
    now = Date.now()
  } = {}) {
    const normalizedMode = normalizePortfolioStatus(mode, 'local_review');
    if (!['dry_run', 'local_review'].includes(normalizedMode)) {
      throw new Error('eval PR open simulation receipts are dry_run/local_review only');
    }
    let proposalReceipt = prMergeProposalReceiptId ? this.getEvalPrMergeProposalReceipt(prMergeProposalReceiptId) : null;
    if (!proposalReceipt && generatedArtifactPromotionReceiptId) {
      proposalReceipt = this.listEvalPrMergeProposalReceipts({ generatedArtifactPromotionReceiptId, limit: 1 })[0] || null;
    }
    if (!proposalReceipt) throw new Error(`eval PR merge proposal receipt not found for PR open simulation: ${prMergeProposalReceiptId || generatedArtifactPromotionReceiptId || 'missing'}`);
    if (proposalReceipt.status !== 'proposal_blocked_external_ci_and_operator_merge') {
      throw new Error('blocked PR merge proposal receipt required before PR open simulation');
    }
    if (proposalReceipt.decision !== 'proposal_prepared_merge_blocked') {
      throw new Error('prepared PR merge proposal decision required before PR open simulation');
    }
    if (
      proposalReceipt.response?.safePrProposalPrepared !== true ||
      proposalReceipt.response?.pullRequestOpened !== false ||
      proposalReceipt.response?.mergeAllowed !== false
    ) {
      throw new Error('PR open simulation requires a safe PR proposal with pull request and merge still blocked');
    }
    const promotionReceipt = this.getEvalGeneratedArtifactPromotionReceipt(proposalReceipt.generated_artifact_promotion_receipt_id);
    const workflowReceipt = this.getEvalCiWorkflowPublicationReceipt(proposalReceipt.ci_workflow_publication_receipt_id);
    const contractReceipt = this.getEvalLiveAdapterContractTestReceipt(proposalReceipt.contract_test_receipt_id);
    const learningRecord = hydratePortfolioRow(db.prepare(`SELECT * FROM portfolio_learning_records WHERE id = ?`).get(proposalReceipt.learning_record_id));
    if (!promotionReceipt || !workflowReceipt || !contractReceipt || !learningRecord) {
      throw new Error('complete PR proposal chain required before PR open simulation');
    }
    if (learningRecord.status !== 'accepted_eval_artifact') {
      throw new Error('accepted eval artifact required before PR open simulation');
    }
    const simulation = normalizeEvalPrOpenSimulationReceipt({
      proposalReceipt,
      promotionReceipt,
      workflowReceipt,
      contractReceipt,
      learningRecord,
      simulationKind,
      decision,
      mode: normalizedMode,
      status,
      summary,
      evidence,
      now
    });
    const simulationResponse = simulation.response_json ? JSON.parse(simulation.response_json) : {};
    if (simulationResponse.prOpenSimulationComplete !== true || simulationResponse.pullRequestSubmitted !== false) {
      throw new Error('non-submitting local PR open simulation required before recording PR open simulation receipt');
    }
    const currentEval = learningRecord.eval && typeof learningRecord.eval === 'object' ? learningRecord.eval : {};
    const apply = db.transaction(() => {
      db.prepare(`
        INSERT OR IGNORE INTO portfolio_eval_pr_open_simulation_receipts (
          id, workspace_id, service_business_id, pr_merge_proposal_receipt_id, generated_artifact_promotion_receipt_id,
          ci_workflow_publication_receipt_id, contract_test_receipt_id, learning_record_id, eval_key,
          simulation_kind, decision, mode, status, pull_request_submitted, summary, request_json,
          response_json, evidence_json, created_at, updated_at
        )
        VALUES (
          @id, @workspace_id, @service_business_id, @pr_merge_proposal_receipt_id, @generated_artifact_promotion_receipt_id,
          @ci_workflow_publication_receipt_id, @contract_test_receipt_id, @learning_record_id, @eval_key,
          @simulation_kind, @decision, @mode, @status, @pull_request_submitted, @summary, @request_json,
          @response_json, @evidence_json, @created_at, @updated_at
        )
      `).run(simulation);
      const persistedSimulation = db.prepare(`
        SELECT *
        FROM portfolio_eval_pr_open_simulation_receipts
        WHERE pr_merge_proposal_receipt_id = ? AND simulation_kind = ?
        ORDER BY created_at DESC
        LIMIT 1
      `).get(proposalReceipt.id, simulation.simulation_kind);
      db.prepare(`
        UPDATE portfolio_learning_records
        SET eval_json = ?,
            updated_at = ?
        WHERE id = ?
      `).run(jsonText({
        ...currentEval,
        prOpenSimulationRecorded: true,
        prOpenSimulationReceiptId: persistedSimulation?.id || simulation.id,
        prOpenSimulationComplete: simulationResponse.prOpenSimulationComplete === true,
        pullRequestSubmitted: false,
        pullRequestOpened: false,
        mergeAllowed: false,
        externalCiResultIngested: false,
        remainingBlockers: simulationResponse.remainingBlockers || []
      }), now, learningRecord.id);
      insertPortfolioEvent({
        workspaceId: simulation.workspace_id,
        entityType: 'eval_pr_open_simulation_receipt',
        entityId: persistedSimulation?.id || simulation.id,
        type: 'portfolio_eval.pr_open_simulation_recorded',
        summary: simulation.summary,
        metadata: {
          serviceBusinessId: simulation.service_business_id,
          prMergeProposalReceiptId: simulation.pr_merge_proposal_receipt_id,
          generatedArtifactPromotionReceiptId: simulation.generated_artifact_promotion_receipt_id,
          ciWorkflowPublicationReceiptId: simulation.ci_workflow_publication_receipt_id,
          learningRecordId: simulation.learning_record_id,
          evalKey: simulation.eval_key,
          decision: simulation.decision,
          pullRequestSubmitted: false,
          mergeAllowed: false
        },
        now
      });
    });
    apply();
    return {
      receipt: this.getEvalPrOpenSimulationReceipt(simulation.id)
        || this.listEvalPrOpenSimulationReceipts({ prMergeProposalReceiptId: proposalReceipt.id, simulationKind: simulation.simulation_kind, limit: 1 })[0],
      prMergeProposalReceipt: this.getEvalPrMergeProposalReceipt(proposalReceipt.id),
      generatedArtifactPromotionReceipt: this.getEvalGeneratedArtifactPromotionReceipt(promotionReceipt.id),
      ciWorkflowPublicationReceipt: this.getEvalCiWorkflowPublicationReceipt(workflowReceipt.id),
      contractReceipt: this.getEvalLiveAdapterContractTestReceipt(contractReceipt.id),
      learningRecord: hydratePortfolioRow(db.prepare(`SELECT * FROM portfolio_learning_records WHERE id = ?`).get(learningRecord.id))
    };
  },

