    const githubPrObservationReceipt = this.getEvalGithubPrObservationReceipt(readinessReceipt.github_pr_observation_receipt_id);
    const githubPrVerificationReceipt = this.getEvalGithubPrVerificationReceipt(readinessReceipt.github_pr_verification_receipt_id);
