      merge_queue_live_read_response_ingestion_receipt_id: handoffReceipt.merge_queue_live_read_response_ingestion_receipt_id,
      merge_queue_runtime_token_release_gate_receipt_id: handoffReceipt.merge_queue_runtime_token_release_gate_receipt_id,
      merge_queue_live_read_verification_promotion_receipt_id: promotionReceipt.id,
