      branch_protection_readback_adapter_contract_receipt_id: handoffReceipt.branch_protection_readback_adapter_contract_receipt_id,
      operator_merge_completion_gate_receipt_id: handoffReceipt.operator_merge_completion_gate_receipt_id,
      merge_execution_adapter_contract_receipt_id: handoffReceipt.merge_execution_adapter_contract_receipt_id,
      github_check_run_observation_receipt_id: handoffReceipt.github_check_run_observation_receipt_id,
      github_pr_observation_receipt_id: handoffReceipt.github_pr_observation_receipt_id,
      github_pr_verification_receipt_id: handoffReceipt.github_pr_verification_receipt_id,
      external_ci_result_receipt_id: handoffReceipt.external_ci_result_receipt_id,
      pr_external_verification_receipt_id: handoffReceipt.pr_external_verification_receipt_id,
