      summary: cleanPortfolioText(summary, 900) || `Recorded merge-queue live HTTP operator release ack for ${handoffReceipt.eval_key} while secret smoke, token release, HTTP, and merge execution remain blocked.`,
      request_json: jsonText({ releaseAckKey: cleanReleaseAckKey, releaseAckKind: cleanKind, decision: cleanDecision, mode: normalizedMode, runtimeSecretRef, requestMethod, releaseScope, acknowledgedRisks, releaseAckChecklist, liveHttpReleasePlan, tokenReleaseApproved: false, httpRequestSent: false, mergeExecuted: false }),
      response_json: jsonText(response),
      evidence_json: jsonText({ operatorEvidence: Array.isArray(evidence) ? evidence : (evidence ? [evidence] : []), liveHttpPreflightHandoff: handoffResponse, releaseAck: releaseAckResult, ...response }),
