          ci_workflow_publication_receipt_id, learning_record_id, eval_key,
          release_ack_key, release_ack_kind, decision, mode, status, release_ack_mode,
          live_http_execution_preflight_handoff_observed, operator_release_ack_recorded,
          operator_live_http_risk_acknowledged, runtime_secret_provider_smoke_required,
          secret_redaction_guardrail_required, http_execution_plan_recorded,
          real_token_observed, token_release_approved, token_released,
          token_materialized, token_value_included, token_value_persisted,
          token_value_logged, authorization_header_materialized, http_request_sent,
          live_read_attempted, live_github_api_called, live_read_succeeded,
          merge_queue_live_verified, live_verification_promoted, github_mutation,
          merge_allowed, merge_executed, live_side_effects, runtime_secret_ref,
