      merge_queue_live_read_verification_promotion_receipt_id: gateReceipt.merge_queue_live_read_verification_promotion_receipt_id,
      merge_queue_live_http_execution_preflight_handoff_receipt_id: gateReceipt.merge_queue_live_http_execution_preflight_handoff_receipt_id,
