          merge_queue_runtime_secret_provider_smoke_execution_gate_receipt_id,
          merge_queue_runtime_secret_provider_smoke_evidence_review_receipt_id,
          merge_queue_memory_only_runtime_token_release_preflight_receipt_id,
          secret_redaction_proof_receipt_id, token_scope_observation_adapter_contract_receipt_id,
          branch_protection_readback_adapter_contract_receipt_id, operator_merge_completion_gate_receipt_id,
          merge_execution_adapter_contract_receipt_id, github_check_run_observation_receipt_id,
          github_pr_observation_receipt_id, github_pr_verification_receipt_id,
          external_ci_result_receipt_id, pr_external_verification_receipt_id,
          submitted_pr_evidence_receipt_id, operator_merge_approval_receipt_id,
          pr_open_simulation_receipt_id, pr_merge_proposal_receipt_id,
          generated_artifact_promotion_receipt_id, ci_workflow_publication_receipt_id,
          learning_record_id, eval_key, smoke_evidence_ingestion_key, smoke_evidence_ingestion_kind,
          decision, mode, status, smoke_evidence_ingestion_mode,
          memory_only_runtime_token_release_preflight_observed, successful_smoke_evidence_submitted,
          successful_smoke_evidence_required, successful_smoke_evidence_accepted,
          successful_smoke_evidence_observed, fake_success_claim_rejected,
          runtime_secret_provider_smoke_verified, memory_only_token_release_allowed,
