  rollbackPortfolioDispatch({
    receiptId = null,
    jobId = null,
    actor = 'system',
    reason = 'operator requested dispatch rollback',
    evidence = [],
    now = Date.now()
  } = {}) {
    const sourceReceipt = receiptId
      ? hydratePortfolioRow(db.prepare(`SELECT * FROM portfolio_dispatch_receipts WHERE id = ?`).get(receiptId))
      : latestPortfolioDispatchReceipt({ jobId, mode: 'dry_run' });
    if (!sourceReceipt) throw new Error('portfolio dispatch receipt not found for rollback');
    const context = portfolioDispatchContext({
      jobId: sourceReceipt.job_id,
      taskId: sourceReceipt.task_id,
      vendorId: sourceReceipt.vendor_id
    });
    const rollback = sourceReceipt.rollback || {};
    if (context.task && rollback.previousTaskStatus) {
      db.prepare(`
        UPDATE portfolio_fulfillment_tasks
        SET status = ?,
            proof_json = ?,
            updated_at = ?
        WHERE id = ?
      `).run(
        rollback.previousTaskStatus,
        jsonText(rollback.previousTaskProof || null),
        now,
        context.task.id
      );
    }
    const receipt = buildPortfolioDispatchReceipt({
      context,
      mode: 'rollback',
      status: 'rolled_back',
      actor,
      proof: {
        reason,
        evidence,
        sourceReceiptId: sourceReceipt.id
      },
      rollbackResponse: {
        restored: true,
        sourceReceiptId: sourceReceipt.id,
        restoredTaskStatus: rollback.previousTaskStatus || null,
        externalSideEffects: false
      },
      now
    });
    db.prepare(`
      INSERT INTO portfolio_dispatch_receipts (
        id, workspace_id, service_business_id, job_id, task_id, vendor_id, provider,
        mode, status, summary, request_json, response_json, rollback_json,
        evidence_json, created_at, updated_at
      )
      VALUES (
        @id, @workspace_id, @service_business_id, @job_id, @task_id, @vendor_id, @provider,
        @mode, @status, @summary, @request_json, @response_json, @rollback_json,
        @evidence_json, @created_at, @updated_at
      )
    `).run(receipt);
    insertPortfolioEvent({
      workspaceId: context.workspaceId,
      entityType: 'portfolio_job',
      entityId: context.job.id,
      type: 'portfolio_dispatch.rolled_back',
      summary: 'Rolled back local dispatch planning state without external booking or field dispatch.',
      metadata: { receiptId: receipt.id, sourceReceiptId: sourceReceipt.id, taskId: context.task?.id || null },
      now
    });
    return {
      receipt: hydratePortfolioRow(db.prepare(`SELECT * FROM portfolio_dispatch_receipts WHERE id = ?`).get(receipt.id)),
      task: context.task ? hydratePortfolioRow(db.prepare(`SELECT * FROM portfolio_fulfillment_tasks WHERE id = ?`).get(context.task.id)) : null,
      job: hydratePortfolioRow(db.prepare(`SELECT * FROM portfolio_jobs WHERE id = ?`).get(context.job.id)),
      vendor: context.vendor
    };
  },

