  const publicationResponse = receipt.response && typeof receipt.response === 'object' ? receipt.response : {};
  const publicationEvidence = receipt.evidence && typeof receipt.evidence === 'object' ? receipt.evidence : {};
  const manifest = publicationResponse.manifest || {};
  const publicationBlockers = Array.isArray(publicationResponse.blockers) ? publicationResponse.blockers : [];
  const evalKey = cleanPortfolioText(receipt.eval_key || manifest.evalKey || `learning_${learningRecord.id}`, 160);
  const laneKeys = Array.isArray(manifest.laneKeys)
    ? manifest.laneKeys
    : Array.isArray(publicationEvidence.laneKeys) ? publicationEvidence.laneKeys : [];
  const workDefinitions = [
    {
      itemKey: 'fixture_spec_review',
      workKind: 'eval_fixture_spec',
      priority: 10,
      summary: `Draft local fixture cases for ${evalKey} from accepted operator handoff evidence.`,
      blockers: ['fixture_schema_review', 'golden_case_selection', 'operator_fixture_approval']
    },
    {
      itemKey: 'harness_binding_review',
      workKind: 'eval_harness_binding',
      priority: 20,
      summary: `Bind ${evalKey} to a non-live regression harness plan without writing executable tests.`,
      blockers: ['eval_harness_binding', 'adapter_contract_review', 'non_live_runner_selection']
    },
    {
      itemKey: 'regression_fixture_review',
      workKind: 'regression_fixture_review',
      priority: 30,
      summary: `Review regression fixtures for ${evalKey} before any executable eval publication.`,
      blockers: ['regression_fixture_review', 'snapshot_review', 'flakiness_guardrail']
    },
    {
      itemKey: 'ci_publication_gate',
      workKind: 'ci_publication_gate',
      priority: 40,
      summary: `Keep CI publication for ${evalKey} blocked until operator and adapter proof exists.`,
      blockers: ['ci_write_access', 'operator_publication_approval', 'live_adapter_implemented']
    }
  ];
  return workDefinitions.map((definition) => {
    const request = {
      itemKey: definition.itemKey,
      workKind: definition.workKind,
      mode: cleanMode,
      publicationReceiptId: receipt.id,
      closeoutId: receipt.closeout_id || closeout?.id || null,
      learningRecordId: learningRecord.id,
      evalKey,
      sourceManifest: manifest,
      localOnly: true
    };
    const response = {
      queued: true,
      status: cleanStatus,
      evalKey,
      laneKeys,
      blockers: definition.blockers,
      publicationBlockers,
      executableEvalPublished: false,
      executablePublicationAllowed: false,
      testFileWritten: false,
      ciWorkflowMutated: false,
      harnessExecuted: false,
      liveAdapterInvoked: false,
      externalPublicationAllowed: false,
      externalPublication: false,
      providerMutation: false,
      customerMessageSent: false,
      liveSideEffects: false,
      operatorReviewRequired: true
    };
    return {
      id: portfolioId('evalwork', `${receipt.id}_${definition.itemKey}`),
      workspace_id: receipt.workspace_id,
      service_business_id: receipt.service_business_id || serviceBusiness?.id || learningRecord.service_business_id || null,
      publication_receipt_id: receipt.id,
      closeout_id: receipt.closeout_id || closeout?.id || null,
      learning_record_id: learningRecord.id,
      eval_key: evalKey,
      item_key: definition.itemKey,
      work_kind: definition.workKind,
      mode: cleanMode,
      status: cleanStatus,
      priority: definition.priority,
      summary: definition.summary,
      request_json: jsonText(request),
      response_json: jsonText(response),
      evidence_json: jsonText({
        publicationReceiptId: receipt.id,
        closeoutId: receipt.closeout_id || closeout?.id || null,
        learningRecordId: learningRecord.id,
        evalKey,
        laneKeys,
        operatorEvidence: Array.isArray(evidence) ? evidence : [],
        localReviewOnly: true,
        executableEvalPublished: false,
        testFileWritten: false,
        ciWorkflowMutated: false,
        liveSideEffectsAllowed: false,
        blockers: definition.blockers
      }),
      created_at: now,
      updated_at: now
    };
  });
