function normalizeEvalFixtureRunnerReceipt({
  publicationReceipt,
  closeout = null,
  learningRecord,
  serviceBusiness = null,
  workItems = [],
  runKind = 'eval_fixture_runner_dry_run',
  mode = 'dry_run',
  status = 'blocked_runner_dry_run',
  summary = '',
  evidence = null,
  now = Date.now()
}) {
  const cleanKind = normalizePortfolioStatus(runKind, 'eval_fixture_runner_dry_run');
  const cleanStatus = normalizePortfolioStatus(status, 'blocked_runner_dry_run');
  const evalKey = cleanPortfolioText(publicationReceipt.eval_key || `learning_${learningRecord.id}`, 160);
  const fixtureItems = Array.isArray(workItems) ? workItems : [];
  const workKinds = [...new Set(fixtureItems.map((item) => item.work_kind).filter(Boolean))];
  const requiredWorkKinds = [
    'eval_fixture_spec',
    'eval_harness_binding',
    'regression_fixture_review',
    'ci_publication_gate'
  ];
  const missingWorkKinds = requiredWorkKinds.filter((kind) => !workKinds.includes(kind));
  const publicationResponse = publicationReceipt.response && typeof publicationReceipt.response === 'object'
    ? publicationReceipt.response
    : {};
  const manifest = publicationResponse.manifest || {};
  const laneKeys = Array.isArray(manifest.laneKeys) ? manifest.laneKeys : [];
  const blockers = [
    ...missingWorkKinds.map((kind) => `${kind}_work_item_required`),
    'operator_fixture_approval',
    'golden_fixture_review',
    'non_live_runner_binding',
    'executable_eval_file_review',
    'ci_write_access',
    'live_adapter_implemented'
  ];
  const response = {
    runnerDryRunRecorded: true,
    status: cleanStatus,
    evalKey,
    fixtureWorkItemCount: fixtureItems.length,
    workKinds,
    requiredWorkKindsPresent: missingWorkKinds.length === 0,
    missingWorkKinds,
    fixtureSpecReviewed: workKinds.includes('eval_fixture_spec'),
    harnessBindingReviewed: workKinds.includes('eval_harness_binding'),
    regressionFixtureReviewed: workKinds.includes('regression_fixture_review'),
    ciPublicationGateReviewed: workKinds.includes('ci_publication_gate'),
    proposedRunner: {
      suite: manifest.suite || 'operator_handoff_regression',
      command: manifest.proposedCommand || 'npm run check:maygoals',
      evalKey,
      nonLiveOnly: true
    },
    blockers,
    executableEvalPublished: false,
    executablePublicationAllowed: false,
    testFileWritten: false,
    ciWorkflowMutated: false,
    harnessExecuted: false,
    liveAdapterInvoked: false,
    externalPublicationAllowed: false,
    providerMutation: false,
    customerMessageSent: false,
    liveSideEffects: false,
    operatorReviewRequired: true
  };
  return {
    id: portfolioId('evalrun', `${publicationReceipt.id}_${cleanKind}_${now}`),
    workspace_id: publicationReceipt.workspace_id,
    service_business_id: publicationReceipt.service_business_id || serviceBusiness?.id || learningRecord.service_business_id || null,
    publication_receipt_id: publicationReceipt.id,
    closeout_id: publicationReceipt.closeout_id || closeout?.id || null,
    learning_record_id: learningRecord.id,
    eval_key: evalKey,
    run_kind: cleanKind,
    mode: normalizePortfolioStatus(mode, 'dry_run'),
    status: cleanStatus,
    fixture_work_item_count: fixtureItems.length,
    summary: cleanPortfolioText(summary, 800)
      || `Recorded local runner dry run for ${evalKey} without writing tests, mutating CI, or executing a harness.`,
    request_json: jsonText({
      runKind: cleanKind,
      mode,
      publicationReceiptId: publicationReceipt.id,
      closeoutId: publicationReceipt.closeout_id || closeout?.id || null,
      learningRecordId: learningRecord.id,
      evalKey,
      fixtureWorkItemIds: fixtureItems.map((item) => item.id),
      localOnly: true
    }),
    response_json: jsonText(response),
    evidence_json: jsonText({
      publicationReceiptId: publicationReceipt.id,
      closeoutId: publicationReceipt.closeout_id || closeout?.id || null,
      learningRecordId: learningRecord.id,
      evalKey,
      laneKeys,
      fixtureWorkItemIds: fixtureItems.map((item) => item.id),
      workKinds,
      operatorEvidence: Array.isArray(evidence) ? evidence : [],
      localReviewOnly: true,
      executableEvalPublished: false,
      testFileWritten: false,
      ciWorkflowMutated: false,
      harnessExecuted: false,
      liveAdapterInvoked: false,
      liveSideEffectsAllowed: false,
      blockers
    }),
    created_at: now,
    updated_at: now
  };
}

