    adapterKey: cleanPortfolioText(contractResult?.adapterKey || adapterPlan.adapterKey || 'operator_handoff_eval_live_adapter', 160),
    suite: cleanPortfolioText(contractResult?.suite || 'operator_handoff_regression', 160),
    fixtureSource: cleanPortfolioText(contractResult?.fixtureSource || 'server/handoff.js', 200),
    executedAt: contractResult?.executedAt || new Date(now).toISOString(),
