function safeReadPortfolioRepoText(relativePath) {
  const clean = cleanPortfolioText(relativePath, 260);
  if (!clean || clean.startsWith('/') || clean.split('/').includes('..')) return '';
  const fullPath = join(process.cwd(), clean);
  if (!existsSync(fullPath)) return '';
  try {
    return readFileSync(fullPath, 'utf8');
  } catch {
    return '';
  }
}

function portfolioTextSha256(value) {
  return createHash('sha256').update(String(value || '')).digest('hex');
}

