function normalizeSubmittedPullRequestUrl(value) {
  const text = cleanPortfolioText(value, 500);
  if (!text) return null;
  try {
    const url = new URL(text);
    const host = url.hostname.toLowerCase();
    if (url.protocol !== 'https:' || host !== 'github.com') return null;
    if (!/\/pull\/\d+(\/)?$/i.test(url.pathname)) return null;
    return url.toString();
  } catch {
    return null;
  }
}

function normalizeExternalCiRunUrl(value) {
  const text = cleanPortfolioText(value, 500);
  if (!text) return null;
  try {
    const url = new URL(text);
    if (url.protocol !== 'https:') return null;
    return url.toString();
  } catch {
    return null;
  }
}

function githubPullRequestApiUrl(value) {
  const prUrl = normalizeSubmittedPullRequestUrl(value);
  if (!prUrl) return null;
  try {
    const url = new URL(prUrl);
    const parts = url.pathname.split('/').filter(Boolean);
    if (parts.length < 4 || parts[2] !== 'pull') return null;
    const [owner, repo, , number] = parts;
    return `https://api.github.com/repos/${owner}/${repo}/pulls/${number}`;
  } catch {
    return null;
  }
}

