function normalizePortfolioContacts(items, lead = null) {
  const source = Array.isArray(items) ? [...items] : [];
  if (lead?.phone) source.push({ kind: 'phone', value: lead.phone, consentStatus: lead.consent_status || 'unknown', source: { type: 'lead', leadId: lead.id } });
  if (lead?.agentmail_thread_id) source.push({ kind: 'email_thread', value: lead.agentmail_thread_id, consentStatus: 'operational', source: { type: 'lead', leadId: lead.id } });
  const seen = new Set();
  return source.map((item) => ({
    kind: normalizePortfolioStatus(item.kind || item.type || 'contact', 'contact'),
    value: cleanPortfolioText(item.value || item.phone || item.email || item.threadId, 240),
    consentStatus: normalizePortfolioStatus(item.consentStatus || item.consent_status || 'unknown', 'unknown'),
    source: item.source || null
  })).filter((item) => {
    const key = `${item.kind}:${item.value}`;
    if (!item.value || seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

