function executedChannelStatusForAction(actionType) {
  const type = normalizePortfolioStatus(actionType, 'review_channel');
  if (type === 'scale_channel') return 'scale';
  if (type === 'hold_or_rework_channel') return 'hold_rework';
  if (type === 'pause_channel') return 'paused';
  if (type === 'continue_capped_test') return 'capped_test';
  if (type === 'optimize_offer_or_price') return 'optimize';
  if (type === 'launch_first_motion') return 'launch_ready';
  return 'reviewed';
}

function channelStrategyStatus({ strategy, channel }) {
  if (strategy.decision === 'scale') {
    return channel.conversions > 0 ? 'scale' : 'hold_rework';
  }
  if (strategy.decision === 'pause') return 'paused';
  if (strategy.decision === 'optimize') return channel.conversions > 0 ? 'optimize' : 'paused';
  return 'watch';
}

