function refreshPortfolioConversionMonitoring({ serviceBusinessId, now = Date.now(), strategy = null } = {}) {
  const serviceBusiness = hydratePortfolioRow(db.prepare(`SELECT * FROM service_businesses WHERE id = ?`).get(serviceBusinessId));
  if (!serviceBusiness) return null;
  const rollup = portfolioAcquisitionRollupForService(serviceBusiness);
  const check = hydratePortfolioRow(db.prepare(`
    SELECT *
    FROM portfolio_monitoring_checks
    WHERE service_business_id = ?
      AND kind = 'conversion_tracking'
    ORDER BY updated_at DESC
    LIMIT 1
  `).get(serviceBusinessId));
  if (!check) return null;
  const status = strategy?.decision === 'pause' ? 'blocked' : rollup.conversions > 0 ? 'active' : 'watch';
  const baseSummary = rollup.conversions > 0
    ? `${rollup.conversions}/${rollup.attempts} acquisition attempts converted with ${formatPortfolioCents(rollup.marginCents)} margin.`
    : `${rollup.attempts} acquisition attempts recorded with no conversion yet.`;
  const summary = strategy?.summary ? `${baseSummary} Strategy: ${strategy.summary}` : baseSummary;
  db.prepare(`
    UPDATE portfolio_monitoring_checks
    SET status = ?,
        summary = ?,
        evidence_json = ?,
        updated_at = ?
    WHERE id = ?
  `).run(status, summary, jsonText([{ source: 'portfolio_acquisition_rollup', rollup }, ...(strategy ? [{ source: 'portfolio_acquisition_strategy', strategy }] : [])]), now, check.id);
  return hydratePortfolioRow(db.prepare(`SELECT * FROM portfolio_monitoring_checks WHERE id = ?`).get(check.id));
}

function formatPortfolioCents(value) {
  const cents = Number(value) || 0;
  const sign = cents < 0 ? '-' : '';
  return `${sign}$${Math.abs(cents / 100).toFixed(2)}`;
}

function formatPortfolioLabel(value) {
  return String(value || 'unknown').replace(/[_-]+/g, ' ');
}

function cleanPortfolioUrl(value) {
  const text = cleanPortfolioText(value, 500);
  if (!/^https?:\/\//i.test(text)) return '';
  return text;
}

function normalizePortfolioSeverity(value) {
  const text = normalizePortfolioStatus(value || 'medium', 'medium');
  if (['low', 'medium', 'high', 'critical'].includes(text)) return text;
  return 'medium';
}

function portfolioDispatchContext({ jobId, taskId = null, vendorId = null } = {}) {
  if (!jobId) throw new Error('jobId is required for portfolio dispatch');
  const job = hydratePortfolioRow(db.prepare(`
    SELECT job.*, customer.name AS customer_name, svc.name AS service_business_name
    FROM portfolio_jobs job
    LEFT JOIN portfolio_customers customer ON customer.id = job.customer_id
    LEFT JOIN service_businesses svc ON svc.id = job.service_business_id
    WHERE job.id = ?
  `).get(jobId));
  if (!job) throw new Error(`portfolio job not found: ${jobId}`);
  const serviceBusiness = hydratePortfolioRow(db.prepare(`SELECT * FROM service_businesses WHERE id = ?`).get(job.service_business_id));
  if (!serviceBusiness) throw new Error(`service business not found for portfolio job: ${jobId}`);
  const tasks = db.prepare(`
    SELECT *
    FROM portfolio_fulfillment_tasks
    WHERE job_id = ?
    ORDER BY updated_at DESC
  `).all(job.id).map(hydratePortfolioRow);
  const task = taskId
    ? tasks.find((item) => item.id === taskId) || null
    : tasks.find((item) => /dispatch|booking|vendor/i.test(`${item.kind} ${item.title} ${item.provider || ''}`)) || tasks[0] || null;
  if (taskId && !task) throw new Error(`portfolio dispatch task not found: ${taskId}`);
  const payments = db.prepare(`
    SELECT *
    FROM portfolio_payments
    WHERE job_id = ?
    ORDER BY updated_at DESC
  `).all(job.id).map(hydratePortfolioRow);
  const approvals = db.prepare(`
    SELECT *
    FROM portfolio_approvals
    WHERE workspace_id = ?
      AND (
        (entity_type = 'portfolio_job' AND entity_id = ?)
        OR (entity_type = 'service_business' AND entity_id = ?)
      )
    ORDER BY updated_at DESC
  `).all(job.workspace_id, job.id, serviceBusiness.id).map(hydratePortfolioRow);
  const providerLinks = db.prepare(`
    SELECT *
    FROM portfolio_provider_links
    WHERE workspace_id = ? AND service_business_id = ?
    ORDER BY updated_at DESC
  `).all(job.workspace_id, serviceBusiness.id).map(hydratePortfolioRow);
  const incidents = db.prepare(`
    SELECT *
    FROM portfolio_incidents
    WHERE workspace_id = ?
      AND (
        job_id = ?
        OR service_business_id = ?
      )
    ORDER BY updated_at DESC
  `).all(job.workspace_id, job.id, serviceBusiness.id).map(hydratePortfolioRow);
  const vendors = serviceBusiness.territory_id
    ? db.prepare(`
      SELECT *
      FROM vendor_partners
      WHERE workspace_id = ?
        AND territory_id = ?
      ORDER BY updated_at DESC
    `).all(job.workspace_id, serviceBusiness.territory_id).map(hydratePortfolioRow)
    : db.prepare(`
      SELECT *
      FROM vendor_partners
      WHERE workspace_id = ?
      ORDER BY updated_at DESC
    `).all(job.workspace_id).map(hydratePortfolioRow);
  const vendor = vendorId
    ? vendors.find((item) => item.id === vendorId) || null
    : vendors.find(isPortfolioVendorReady) || vendors[0] || null;
  if (vendorId && !vendor) throw new Error(`vendor partner not found for dispatch: ${vendorId}`);
  return {
    workspaceId: job.workspace_id,
    serviceBusiness,
    job,
    task,
    tasks,
    payments,
    approvals,
    providerLinks,
    incidents,
    vendors,
    vendor
  };
}

function latestPortfolioDispatchReceipt({ jobId, mode = null, provider = 'booking_dispatch_adapter' } = {}) {
  if (!jobId) return null;
  const where = ['job_id = ?', 'provider = ?'];
  const params = [jobId, provider];
  if (mode) {
    where.push('mode = ?');
    params.push(mode);
  }
  const row = db.prepare(`
    SELECT *
    FROM portfolio_dispatch_receipts
    WHERE ${where.join(' AND ')}
    ORDER BY created_at DESC
    LIMIT 1
  `).get(...params);
  return hydratePortfolioRow(row);
}

function buildPortfolioDispatchSafetyProof({ context, mode }) {
  const vendor = context.vendor;
  return {
    kind: 'booking_dispatch_motion_safety',
    provider: 'booking_dispatch_adapter',
    mode,
    serviceBusinessId: context.serviceBusiness.id,
    serviceBusinessName: context.serviceBusiness.name,
    jobId: context.job.id,
    jobTitle: context.job.title,
    taskId: context.task?.id || null,
    vendorId: vendor?.id || null,
    vendorName: vendor?.name || null,
    status: 'plan_only_no_booking_or_dispatch_created',
    externalSideEffects: false,
    bookingId: null,
    dispatchId: null,
    customerScopeApprovalRequired: true,
    paymentAuthorizationRequired: true,
    safeToFulfillGateRequired: true,
    vendorBenchRequired: true,
    vendorLicenseVerificationRequired: true,
    vendorInsuranceVerificationRequired: true,
    serviceAreaCoverageRequired: true,
    capacityWindowRequired: true,
    slaPromiseReviewRequired: true,
    calendarSlotProofRequired: true,
    customerConfirmationRequired: true,
    vendorAcceptanceRequired: true,
    priceAndPayoutBoundaryRequired: true,
    marginFloorRequired: true,
    emergencyClaimReviewRequired: true,
    customerUpdatePolicyRequired: true,
    providerLiveSmokeRequired: true,
    liveAdapterImplemented: false,
    liveSmokeCommand: 'SMOKE_LIVE_CALL=true SMOKE_TEST_PHONE=<owned-number> npm run smoke:providers -- --provider agentphone',
    policySources: [
      'maygoals.Calendar and dispatch',
      'maygoals.Real Fulfillment, Not Just Digital Delivery',
      'portfolio safe_to_fulfill gate',
      'vendor_partners compliance ledger',
      'server/scheduledCalls callback gates'
    ],
    channelPlan: {
      jobStatus: context.job.status,
      taskStatus: context.task?.status || null,
      vendorStatus: vendor?.status || null,
      paymentStatuses: context.payments.map((payment) => payment.status),
      approvals: context.approvals.map((approval) => ({ kind: approval.kind, status: approval.status }))
    },
    evidence: {
      noBookingCreated: true,
      noCalendarSlotReserved: true,
      noVendorAssigned: true,
      noCustomerPromiseSent: true,
      noFieldDispatchStarted: true,
      rollbackPath: context.task ? 'portfolio_fulfillment_tasks.status/proof_json' : 'portfolio_jobs.evidence_json'
    }
  };
}

function buildPortfolioDispatchPreflight({ context, allowLiveDispatch = false, now = Date.now() }) {
  const latestDryRunReceipt = latestPortfolioDispatchReceipt({ jobId: context.job.id, mode: 'dry_run' });
  const gateContext = portfolioGateContext(context.serviceBusiness);
  const serviceGates = buildPortfolioGateEvaluations(gateContext);
  const fulfillGate = serviceGates.find((gate) => gate.key === 'safe_to_fulfill');
  const latestPayment = context.payments[0] || null;
  const paymentAuthorized = latestPayment ? ['authorized', 'paid', 'succeeded', 'completed'].includes(latestPayment.status) : false;
  const vendorReady = context.vendor ? isPortfolioVendorReady(context.vendor) : false;
  const vendorCompliance = context.vendor?.compliance || {};
  const vendorPayout = context.vendor?.payout || {};
  const vendorCostCapCents = boundedCents(
    vendorPayout.maxVendorCostCents ?? vendorPayout.costCapCents ?? vendorPayout.estimatedCostCents,
    null
  );
  const minMarginCents = boundedCents(vendorPayout.minMarginCents ?? vendorPayout.marginFloorCents, 0) || 0;
  const expectedMarginCents = vendorCostCapCents === null || context.job.price_cents === null
    ? null
    : Number(context.job.price_cents) - vendorCostCapCents;
  const payoutMarginBoundaryOk = Number.isFinite(expectedMarginCents)
    && expectedMarginCents >= minMarginCents
    && expectedMarginCents > 0;
  const vendorComplianceOk = Boolean(
    vendorReady &&
    (
      vendorCompliance.licenseReview ||
      vendorCompliance.licenseVerification === true ||
      vendorCompliance.licenseVerificationRequired === false
    ) &&
    (
      vendorCompliance.insuranceReview ||
      vendorCompliance.insuranceVerified === true ||
      vendorCompliance.insuranceRequired === false
    )
  );
  const dispatchEvidenceOk = context.task?.proof?.dispatchEvidence?.ok === true || context.job.evidence?.some?.((item) => item?.dispatchEvidence === true) === true;
  const providerLiveSmoke = providerSmoke.latestEvent({ provider: 'agentphone', live: true, statuses: ['ok'] });
  const liveMode = ['demo_live', 'autonomous_live', 'production_live'].includes(env.runMode);
  const sideEffectAllowed = env.live?.calls === true;
  const gates = [
    {
      key: 'dry_run_receipt',
      ok: !!latestDryRunReceipt,
      summary: latestDryRunReceipt ? 'Dry-run dispatch receipt exists.' : 'A validated dry-run dispatch receipt is required before live dispatch preflight can pass.',
      evidence: latestDryRunReceipt ? { receiptId: latestDryRunReceipt.id, provider: latestDryRunReceipt.provider } : null
    },
    {
      key: 'run_mode',
      ok: liveMode,
      summary: 'Run mode must be demo_live, autonomous_live, or production_live before live booking or dispatch side effects.',
      evidence: { runMode: env.runMode }
    },
    {
      key: 'side_effect_flag',
      ok: sideEffectAllowed,
      summary: 'LIVE_CALLS must be enabled before vendor/customer dispatch calls or callback-style dispatch coordination.',
      evidence: { sideEffectKey: 'calls', enabled: sideEffectAllowed }
    },
    {
      key: 'live_dispatch_guardrail',
      ok: allowLiveDispatch === true,
      summary: 'The operator preflight request must explicitly allow live dispatch coordination.',
      evidence: { operatorAllowsLiveDispatch: allowLiveDispatch === true }
    },
    {
      key: 'safe_to_fulfill',
      ok: fulfillGate?.ok === true,
      summary: 'The service business safe_to_fulfill gate must be allowed before dispatch.',
      evidence: fulfillGate ? { decision: fulfillGate.decision, blockers: fulfillGate.blockers } : null
    },
    {
      key: 'customer_scope_approval',
      ok: context.approvals.some((approval) => approval.kind === 'customer_scope_approval' && approval.status === 'approved'),
      summary: 'Customer scope approval must be approved before booking or dispatch.',
      evidence: context.approvals.filter((approval) => approval.kind === 'customer_scope_approval').map((approval) => ({ id: approval.id, status: approval.status }))
    },
    {
      key: 'payment_authorized',
      ok: paymentAuthorized,
      summary: 'Payment must be authorized or collected before field dispatch.',
      evidence: latestPayment ? { id: latestPayment.id, provider: latestPayment.provider, status: latestPayment.status, amountCents: latestPayment.amount_cents } : null
    },
    {
      key: 'vendor_ready',
      ok: vendorReady,
      summary: 'A ready, approved, verified, or contracted vendor partner must exist before dispatch.',
      evidence: context.vendor ? { id: context.vendor.id, name: context.vendor.name, status: context.vendor.status } : null
    },
    {
      key: 'vendor_compliance',
      ok: vendorComplianceOk,
      summary: 'Vendor license and insurance/coverage checks must be verified before dispatch.',
      evidence: context.vendor ? { id: context.vendor.id, compliance: context.vendor.compliance || null } : null
    },
    {
      key: 'payout_margin_boundary',
      ok: payoutMarginBoundaryOk,
      summary: 'Vendor payout must preserve a positive margin floor before assignment or dispatch.',
      evidence: context.vendor ? {
        jobPriceCents: context.job.price_cents,
        maxVendorCostCents: vendorCostCapCents,
        minMarginCents,
        expectedMarginCents,
        payout: context.vendor.payout || null
      } : null
    },
    {
      key: 'dispatch_task_evidence',
      ok: dispatchEvidenceOk,
      summary: 'Dispatch requires capacity window, service-area coverage, SLA boundaries, calendar slot proof, customer confirmation, vendor acceptance, and payout boundary evidence.',
      evidence: context.task ? { taskId: context.task.id, proof: context.task.proof || null } : null
    },
    {
      key: 'provider_live_smoke',
      ok: !!providerLiveSmoke,
      summary: 'Dispatch coordination requires an AgentPhone live smoke before any live vendor/customer call motion.',
      evidence: {
        provider: 'agentphone',
        latestOkLiveSmokeId: providerLiveSmoke?.id || null,
        latestOkLiveSmokeAt: providerLiveSmoke?.checkedAt || null,
        smokeCommand: 'SMOKE_LIVE_CALL=true SMOKE_TEST_PHONE=<owned-number> npm run smoke:providers -- --provider agentphone'
      }
    },
    {
      key: 'live_adapter_implemented',
      ok: false,
      summary: 'booking_dispatch_adapter live adapter must be implemented and smoke-tested.',
      evidence: {
        provider: 'booking_dispatch_adapter',
        operation: 'booking_dispatch_plan',
        implemented: false,
        liveImplementation: 'blocked_until_dispatch_provider_smoke_vendor_compliance_and_calendar_evidence'
      }
    }
  ];
  const blockers = gates.filter((gate) => !gate.ok).map((gate) => gate.key);
  return {
    ready: blockers.length === 0,
    mode: 'live_preflight',
    checkedAt: new Date(now).toISOString(),
    blockers,
    gates,
    externalSideEffects: false
  };
}

function buildPortfolioDispatchReceipt({
  context,
  mode,
  status,
  actor,
  proof = {},
  preflight = null,
  rollbackResponse = null,
  now = Date.now()
}) {
  const provider = 'booking_dispatch_adapter';
  const providerSafety = buildPortfolioDispatchSafetyProof({ context, mode });
  const operation = mode === 'live_preflight'
    ? 'booking_dispatch_live_preflight'
    : mode === 'rollback'
      ? 'booking_dispatch_rollback'
      : 'booking_dispatch_plan';
  const summary = mode === 'rollback'
    ? 'Rolled back local booking/dispatch planning state without external dispatch side effects.'
    : mode === 'live_preflight'
      ? 'Checked live booking/dispatch gates without creating bookings, assigning vendors, reserving calendar slots, or dispatching field work.'
      : 'Validated booking/dispatch requirements without creating bookings, assigning vendors, reserving calendar slots, or dispatching field work.';
  const request = {
    operation,
    actor,
    mode,
    jobId: context.job.id,
    taskId: context.task?.id || null,
    vendorId: context.vendor?.id || null,
    serviceBusinessId: context.serviceBusiness.id,
    providerSafety,
    proof: proof || {}
  };
  const response = rollbackResponse || {
    dryRun: mode === 'dry_run',
    ready: preflight?.ready === true,
    blockers: preflight?.blockers || [],
    gates: preflight?.gates || [],
    externalSideEffects: false,
    firstPartySideEffects: mode === 'dry_run',
    providerSafety
  };
  const rollback = {
    restorePath: context.task ? 'portfolio_fulfillment_tasks.status/proof_json' : 'portfolio_jobs.evidence_json',
    previousTaskStatus: context.task?.status || null,
    previousTaskProof: context.task?.proof || null,
    noBookingCreated: true,
    noCalendarSlotReserved: true,
    noVendorAssigned: true,
    noCustomerPromiseSent: true,
    noFieldDispatchStarted: true
  };
  const evidence = [
    ...(Array.isArray(context.job.evidence) ? context.job.evidence : []),
    ...(Array.isArray(proof?.evidence) ? proof.evidence : []),
    { source: 'portfolio_dispatch_adapter', provider, mode },
    { source: 'portfolio_dispatch_safety', provider, proof: providerSafety.evidence }
  ];
  return {
    id: portfolioDispatchReceiptId(context.job.id, provider, now),
    workspace_id: context.workspaceId,
    service_business_id: context.serviceBusiness.id,
    job_id: context.job.id,
    task_id: context.task?.id || null,
    vendor_id: context.vendor?.id || null,
    provider,
    mode,
    status,
    summary,
    request_json: jsonText(request),
    response_json: jsonText(response),
    rollback_json: jsonText(rollback),
    evidence_json: jsonText(evidence),
    created_at: now,
    updated_at: now
  };
}

function normalizePortfolioEtaMinutes(value) {
  const n = Number(value);
  if (!Number.isFinite(n) || n < 1) return 90;
  return Math.max(1, Math.min(24 * 60, Math.round(n)));
}

function portfolioJobTrackingContext({
  jobId,
  taskId = null,
  vendorId = null,
  trackingStage = 'vendor_eta_photo_status',
  etaMinutes = 90,
  now = Date.now()
} = {}) {
  const context = portfolioDispatchContext({ jobId, taskId: null, vendorId });
  const task = taskId
    ? context.tasks.find((item) => item.id === taskId) || null
    : context.tasks.find((item) => /tracking|operating.?room|eta|photo|portal|status|visibility/i.test(`${item.kind} ${item.title} ${item.provider || ''}`)) || context.task || context.tasks[0] || null;
  if (taskId && !task) throw new Error(`portfolio job tracking task not found: ${taskId}`);
  const customer = context.job.customer_id
    ? hydratePortfolioRow(db.prepare(`SELECT * FROM portfolio_customers WHERE id = ?`).get(context.job.customer_id))
    : null;
  const normalizedEtaMinutes = normalizePortfolioEtaMinutes(etaMinutes);
  const etaAt = now + normalizedEtaMinutes * 60 * 1000;
  return {
    ...context,
    task,
    customer,
    trackingStage: normalizePortfolioStatus(trackingStage || 'vendor_eta_photo_status', 'vendor_eta_photo_status'),
    etaMinutes: normalizedEtaMinutes,
    etaAt
  };
}

function latestPortfolioJobTrackingReceipt({ jobId, mode = null, provider = 'customer_job_tracker' } = {}) {
  if (!jobId) return null;
  const where = ['job_id = ?', 'provider = ?'];
  const params = [jobId, provider];
  if (mode) {
    where.push('mode = ?');
    params.push(mode);
  }
  const row = db.prepare(`
    SELECT *
    FROM portfolio_job_tracking_receipts
    WHERE ${where.join(' AND ')}
    ORDER BY created_at DESC
    LIMIT 1
  `).get(...params);
  return hydratePortfolioRow(row);
}

