    customerId: context.customer?.id || null,
    customerName: context.customer?.name || null,
    vendorId: context.vendor?.id || null,
    vendorName: context.vendor?.name || null,
    status: 'plan_only_no_customer_tracker_eta_promise_photo_exposure_or_status_mutation',
    externalSideEffects: false,
    trackerPublished: false,
    etaPromised: false,
    photoExposed: false,
    customerMessageSent: false,
    jobStatusMutated: false,
    vendorGpsShared: false,
    dispatchReceiptRequired: true,
    vendorEtaEvidenceRequired: true,
    photoPermissionRequired: true,
    photoRedactionRequired: true,
    statusCopyApprovalRequired: true,
