function portfolioCompletionContext({ jobId, taskId = null, vendorId = null } = {}) {
  const context = portfolioDispatchContext({ jobId, taskId: null, vendorId });
  const task = taskId
    ? context.tasks.find((item) => item.id === taskId) || null
    : context.tasks.find((item) => /completion|proof|sla|acceptance|quality/i.test(`${item.kind} ${item.title} ${item.provider || ''}`)) || context.tasks[0] || null;
  if (taskId && !task) throw new Error(`portfolio completion task not found: ${taskId}`);
  return { ...context, task };
}

function latestPortfolioCompletionReceipt({ jobId, mode = null, provider = 'completion_proof_adapter' } = {}) {
  if (!jobId) return null;
  const where = ['job_id = ?', 'provider = ?'];
  const params = [jobId, provider];
  if (mode) {
    where.push('mode = ?');
    params.push(mode);
  }
  const row = db.prepare(`
    SELECT *
    FROM portfolio_completion_receipts
    WHERE ${where.join(' AND ')}
    ORDER BY created_at DESC
    LIMIT 1
  `).get(...params);
  return hydratePortfolioRow(row);
}

