    customerName: context.customer?.name || null,
    contactId: context.contact?.id || null,
    contactKind: context.contact?.kind || null,
    providerLinkRequired: context.channelConfig.requiredProviderLink,
    status: 'plan_only_no_customer_message_sent_or_job_status_mutation',
    externalSideEffects: false,
    customerMessageSent: false,
    emailSent: false,
    smsSent: false,
    callPlaced: false,
    chatMessagePublished: false,
