    liveSmokeCommand: context.channelConfig.liveSmokeCommand,
    policySources: [
      'maygoals.Job acceptance/status/customer updates',
      'maygoals.Customer Operating Rooms For Every Service',
      'portfolio customer contact consent ledger',
      'portfolio vendor quality routing blockers',
      'server/readiness live communication gates'
    ],
