  if (counts.evalMergeQueueMemoryOnlyRuntimeTokenReleasePreflightReceipts && !counts.evalMergeQueueSuccessfulSmokeEvidenceIngestionReceipts) gaps.push('eval_merge_queue_successful_smoke_evidence_ingestion_receipts_missing');
