  if (counts.evalMergeQueueRuntimeTokenReleaseDenialReceipts && !counts.evalMergeQueueFakeLiveReadReplayQuarantineReceipts) gaps.push('eval_merge_queue_fake_live_read_replay_quarantine_receipts_missing');
