  if (counts.acquisitionAttempts && !counts.strategyRecommendations) gaps.push('acquisition_strategy_recommendations_missing');
  if (counts.strategyRecommendations && !counts.acquisitionActions) gaps.push('acquisition_action_queue_missing');
