  if (counts.dispatchReceipts && !counts.jobTrackingReceipts) gaps.push('customer_operating_room_tracking_receipts_missing');
  if (counts.fulfillmentTasks && !counts.completionReceipts) gaps.push('completion_proof_receipts_missing');
  if (counts.completionReceipts && !counts.payoutReceipts) gaps.push('payout_settlement_receipts_missing');
  if (counts.payoutReceipts && !counts.refundDisputeReceipts) gaps.push('refund_dispute_receipts_missing');
  if (counts.dispatchReceipts && !counts.vendorQualityReceipts) gaps.push('vendor_quality_routing_receipts_missing');
  if (counts.vendorQualityReceipts && !counts.customerUpdateReceipts) gaps.push('customer_status_update_receipts_missing');
  if ((counts.completionReceipts || counts.customerUpdateReceipts) && !counts.customerFeedbackRecords) gaps.push('customer_feedback_records_missing');
  if (counts.customerFeedbackRecords && !counts.customerRemediationPlans) gaps.push('customer_remediation_plans_missing');
  if (counts.customerRemediationPlans && !counts.vendorCorrectiveActions) gaps.push('vendor_corrective_actions_missing');
