  if (counts.remediationCloseoutReceipts && !counts.customerRetentionPlaybooks) gaps.push('customer_retention_playbooks_missing');
  if (counts.customerRetentionPlaybooks && !counts.customerRetentionPlaybookReceipts) gaps.push('customer_retention_playbook_receipts_missing');
  if (counts.customerRetentionPlaybookReceipts && !counts.retentionCohortRollups) gaps.push('retention_cohort_rollups_missing');
